const items = $input.all();

if (items.length === 0 || !items[0].json.id_ticket) {
  return [{
    json: {
      mensaje: "📭 No tienes solicitudes registradas aún.\n\nEscribe *1* para crear tu primera solicitud."
    }
  }];
}

let texto = `📋 *Tus solicitudes (${items.length}):*\n\n`;

for (const item of items) {
  const t = item.json;
  const estado = t.estado || 'Sin estado';
  const tipo = t.tipo || 'Sin tipo';
  const fecha = t.fecha_creacion ? t.fecha_creacion.substring(0, 10) : 'Sin fecha';

  texto += `🎫 *${t.id_ticket}*\n`;
  texto += `   📌 ${tipo} | 🚦 ${estado}\n`;
  texto += `   📝 ${t.descripcion}\n`;
  texto += `   📅 ${fecha}\n\n`;
}

texto += `Escribe *2* para consultar el detalle de un ticket específico.`;

return [{ json: { mensaje: texto } }];

const items = $input.all();

const total = items.length;

if (total === 0 || !items[0].json.id_ticket) {
  return [{
    json: {
      mensaje: "\u{1F4CA} *Reporte de Solicitudes*\n\n\u{1F4ED} No hay solicitudes registradas aun en el sistema."
    }
  }];
}

const porEstado = {};
const porTipo = {};
const porPrioridad = {};

for (const item of items) {
  const t = item.json;
  const estado = (t.estado || 'Sin estado').trim();
  const tipo = (t.tipo || 'Sin tipo').trim();
  const prioridad = (t.prioridad || 'Sin prioridad').trim();

  porEstado[estado] = (porEstado[estado] || 0) + 1;
  porTipo[tipo] = (porTipo[tipo] || 0) + 1;
  porPrioridad[prioridad] = (porPrioridad[prioridad] || 0) + 1;
}

const iconosEstado = {
  'ABIERTO': '\uD83D\uDFE2',
  'Pendiente': '\uD83D\uDFE1',
  'En revision': '\uD83D\uDD35',
  'Aprobada': '\u2705',
  'Completada': '\uD83C\uDFC1',
};

const iconosTipo = {
  'Soporte tecnico': '\uD83D\uDEE0\uFE0F',
  'Solicitud administrativa': '\uD83D\uDCCB',
  'Consulta general': '\uD83D\uDCAC',
};

const iconosPrioridad = {
  'Baja': '\uD83D\uDFE2',
  'Media': '\uD83D\uDFE1',
  'Alta': '\uD83D\uDD34',
};

let msg = "\u{1F4CA} *Reporte General de Solicitudes*\n";
msg += "----------------------------\n";
msg += "\u{1F4C1} *Total de solicitudes:* " + total + "\n\n";

msg += "\u{1F4CC} *Por Estado:*\n";
for (const [estado, cantidad] of Object.entries(porEstado)) {
  const icono = iconosEstado[estado] || '\u26AA';
  msg += "   " + icono + " " + estado + ": *" + cantidad + "*\n";
}

msg += "\n\u{1F5C2}\uFE0F *Por Tipo:*\n";
for (const [tipo, cantidad] of Object.entries(porTipo)) {
  const icono = iconosTipo[tipo] || '\uD83D\uDCC4';
  msg += "   " + icono + " " + tipo + ": *" + cantidad + "*\n";
}

msg += "\n\u26A1 *Por Prioridad:*\n";
for (const [prio, cantidad] of Object.entries(porPrioridad)) {
  const icono = iconosPrioridad[prio] || '\u26AA';
  msg += "   " + icono + " " + prio + ": *" + cantidad + "*\n";
}

msg += "\n----------------------------";

return [{ json: { mensaje: msg } }];

const items = $input.all();

const mapasTipo = {
  '1': 'Soporte técnico',
  '2': 'Solicitud administrativa',
  '3': 'Consulta general'
};
const mapasPrioridad = {
  '1': 'Baja',
  '2': 'Media',
  '3': 'Alta'
};

let tipo = '';
let prioridad = '';

// Ordenar descendente por timestamp para tomar los más recientes
const sorted = items
  .filter(i => i.json && i.json.pantalla)
  .sort((a, b) => new Date(b.json.timestamp) - new Date(a.json.timestamp));

for (const item of sorted) {
  const pantalla = (item.json.pantalla || '').trim();
  const opcion   = String(item.json.opcion || '').trim();

  // El tipo se eligió cuando estaba en ESPERANDO_TIPO
  // → el SIGUIENTE log es ESPERANDO_PRIORIDAD y su "opcion" es el número del tipo
  if (pantalla === 'ESPERANDO_PRIORIDAD' && tipo === '') {
    tipo = mapasTipo[opcion] || opcion;
  }
  // La prioridad se eligió cuando estaba en ESPERANDO_PRIORIDAD
  // → el SIGUIENTE log es ESPERANDO_DESCRIPCION y su "opcion" es el número de prioridad
  if (pantalla === 'ESPERANDO_DESCRIPCION' && prioridad === '') {
    prioridad = mapasPrioridad[opcion] || opcion;
  }
  if (tipo !== '' && prioridad !== '') break;
}

return [{ json: { tipo_solicitud: tipo || 'Sin tipo', prioridad_solicitud: prioridad || 'Sin prioridad' } }];

const items = $input.all();

const totalSolicitudes = items.filter(i => i.json && i.json.id_ticket).length;

if (totalSolicitudes === 0) {
  return [{
    json: {
      mensaje: "📊 *Reporte de solicitudes*\n\nNo hay solicitudes registradas aún en el sistema."
    }
  }];
}

// Agrupar por tipo y por estado dentro de cada tipo
const porTipo = {};

for (const item of items) {
  const t = item.json;
  if (!t.id_ticket) continue;

  const tipo   = (t.tipo   || 'Sin tipo').trim();
  const estado = (t.estado || 'Sin estado').trim();

  if (!porTipo[tipo]) {
    porTipo[tipo] = { total: 0, estados: {} };
  }
  porTipo[tipo].total++;
  porTipo[tipo].estados[estado] = (porTipo[tipo].estados[estado] || 0) + 1;
}

// Tipo más frecuente
let tipoMasFrecuente = '';
let maxCount = 0;
for (const [tipo, info] of Object.entries(porTipo)) {
  if (info.total > maxCount) {
    maxCount = info.total;
    tipoMasFrecuente = tipo;
  }
}

// Construir mensaje con Markdown V1 (sin escapes especiales)
let msg = '📊 *Reporte de solicitudes*\n\n';
msg += '*Resumen general*\n';
msg += '- Tipo más frecuente: ' + tipoMasFrecuente + '\n';
msg += '- Total solicitudes: ' + totalSolicitudes + '\n';
msg += '- Interacciones con el bot: {{TOTAL_LOGS}}\n\n';
msg += '*Detalle por tipo*\n';

const tiposOrdenados = Object.entries(porTipo)
  .sort((a, b) => b[1].total - a[1].total);

const numerales = ['1)', '2)', '3)', '4)', '5)'];

tiposOrdenados.forEach(([tipo, info], idx) => {
  const num = numerales[idx] || (idx + 1) + ')';
  msg += '\n' + num + ' ' + tipo + '\n';
  msg += '   - Total: ' + info.total + '\n';

  const ordenEstados = ['ABIERTO', 'Pendiente', 'En revisión', 'En proceso', 'Aprobada', 'Completada', 'Cerrada'];
  const estadosPresentes = Object.assign({}, info.estados);

  for (const est of ordenEstados) {
    if (estadosPresentes[est] !== undefined) {
      msg += '   - ' + est + ': ' + estadosPresentes[est] + '\n';
      delete estadosPresentes[est];
    }
  }
  for (const [est, cant] of Object.entries(estadosPresentes)) {
    msg += '   - ' + est + ': ' + cant + '\n';
  }
});

return [{ json: { mensaje: msg } }];

// Input 0: solicitudes (viene de Leer_Todas_Solicitudes via Code_Calcular_Reporte_V2)
// Input 1: logs (viene de Leer_Logs_Reporte)
// Pero en n8n con merge usamos otra estrategia:
// Este nodo recibe el mensaje del reporte (que tiene {{TOTAL_LOGS}}) y lo reemplaza

const msgItem  = $('Code_Calcular_Reporte_V2').item;
const logsItems = $('Leer_Logs_Reporte').all();

const totalLogs = logsItems.filter(i => i.json && i.json.telegram_user).length;

const mensajeFinal = msgItem.json.mensaje.replace('{{TOTAL_LOGS}}', String(totalLogs));

return [{ json: { mensaje: mensajeFinal } }];
